105	fn parse_cards_bin_csv(
106	    data: &[u8],
107	) -> csv::Result<Vec<cards_info_api_types::CardInfoUpdateRequest>> {
108	    let mut csv_reader = Reader::from_reader(data);
109	    let mut records = Vec::new();
110	    let mut id_counter = 0;
111	    for result in csv_reader.deserialize() {
112	        let mut record: cards_info_api_types::CardInfoUpdateRequest = result?;
113	        id_counter += 1;
114	        record.line_number = Some(id_counter);
115	        records.push(record);
116	    }
117	    Ok(records)
118	}
