120	pub fn get_cards_bin_records(
121	    form: CardsInfoUpdateForm,
122	) -> Result<Vec<cards_info_api_types::CardInfoUpdateRequest>, errors::ApiErrorResponse> {
123	    match parse_cards_bin_csv(form.file.data.to_bytes()) {
124	        Ok(records) => Ok(records),
125	        Err(e) => Err(errors::ApiErrorResponse::PreconditionFailed {
126	            message: e.to_string(),
127	        }),
128	    }
129	}
