132	pub async fn migrate_cards_info(
133	    state: routes::SessionState,
134	    card_info_records: Vec<cards_info_api_types::CardInfoUpdateRequest>,
135	) -> RouterResponse<Vec<cards_info_api_types::CardInfoMigrationResponse>> {
