138	        let res = card_info_flow(record.clone(), state.clone()).await;
139	        result.push(cards_info_api_types::CardInfoMigrationResponse::from((
140	            match res {
141	                Ok(ApplicationResponse::Json(response)) => Ok(response),
142	                Err(e) => Err(e.to_string()),
143	                _ => Err("Failed to migrate card info".to_string()),
144	            },
145	            record,
146	        )));
147	    }
148	    Ok(ApplicationResponse::Json(result))
149	}
