312	async fn card_info_flow(
313	    record: cards_info_api_types::CardInfoUpdateRequest,
314	    state: routes::SessionState,
315	) -> RouterResponse<cards_info_api_types::CardInfoMigrateResponseRecord> {
316	    let builder = CardInfoBuilder::new();
317	    let executor = CardInfoMigrateExecutor::new(&state, &record);
318	    let fetched_card_info_details = executor.fetch_card_info().await?;
319	
320	    let builder = match fetched_card_info_details {
321	        Some(card_info) => {
322	            let builder = builder.set_card_info(card_info);
323	            let updated_card_info = executor.update_card_info().await?;
324	            builder.set_updated_card_info(updated_card_info)
325	        }
326	        None => {
327	            let builder = builder.transition();
328	            let added_card_info = executor.add_card_info().await?;
329	            builder.set_added_card_info(added_card_info)
330	        }
331	    };
332	
333	    Ok(ApplicationResponse::Json(builder.build()))
334	}
